:root {
  /* Core palette */
  --color-primary-black: #000000;
  --color-primary-white: #ffffff;
  --color-secondary-light: #E0E5EA;
  --color-secondary-soft: #F3F4F6;
  --color-accent-red: #D32F2F;
  --color-neutral-mid: #777777;

  /* Semantic */
  --color-success: #2E7D32;
  --color-error: #D32F2F;
  --color-warning: #ED6C02;
  --color-info: #0288D1;

  /* Typography */
  --font-heading: 'Great Vibes', Georgia, serif;
  --font-body: 'DM Sans', Helvetica, sans-serif;
  --font-code: 'Source Code Pro', monospace;

  --font-size-body: 16px;
  --font-size-small: 13px;
  --font-size-h1: 40px;
  --font-size-h2: 32px;
  --font-size-h3: 24px;

  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.75;

  /* Spacing scale (8px base) */
  --space-0-5: 4px;
  --space-1: 8px;
  --space-2: 16px;
  --space-3: 24px;
  --space-4: 32px;
  --space-5: 48px;
  --space-6: 64px;

  /* Layout */
  --max-width: 1120px;
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body {
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-primary-black);
  background-color: var(--color-primary-white);
}

img {
  max-width: 100%;
  display: block;
}

a {
  color: inherit;
}

a:hover,
a:focus {
  text-decoration: none;
}

.container {
  max-width: var(--max-width);
  margin: 0 auto;
  padding: 0 var(--space-3);
}

.site-header {
  background-color: var(--color-primary-black);
  color: var(--color-primary-white);
}

.header-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: var(--space-2) var(--space-4);
  gap: var(--space-3);
}

.brand {
  text-decoration: none;
  color: var(--color-primary-white);
  text-transform: uppercase;
  letter-spacing: 0.24em;
  font-weight: var(--font-weight-semibold);
  font-size: 15px;
  white-space: nowrap;
}

.brand-text {
  border-bottom: 1px solid var(--color-primary-white);
  padding-bottom: 2px;
}

.primary-nav {
  flex: 1 1 auto;
}

.primary-nav ul {
  display: flex;
  justify-content: center;
  align-items: center;
  gap: var(--space-4);
  list-style: none;
  margin: 0;
  padding: 0;
}

.primary-nav a {
  position: relative;
  display: inline-block;
  padding: var(--space-1) 0;
  font-size: 18px;
  font-weight: var(--font-weight-regular);
  color: var(--color-primary-white);
  text-decoration: none;
}

.primary-nav a::after {
  content: '';
  position: absolute;
  left: 0;
  right: 0;
  bottom: 0;
  height: 2px;
  background-color: var(--color-primary-white);
  opacity: 0;
  transform: scaleX(0.6);
  transition: opacity 0.15s ease, transform 0.15s ease;
}

.primary-nav a:hover::after,
.primary-nav a:focus-visible::after,
.primary-nav li.is-active a::after,
.primary-nav a.is-active::after {
  opacity: 1;
  transform: scaleX(1);
}

.primary-nav a:hover,
.primary-nav a:focus-visible {
  color: var(--color-secondary-light);
}

.header-shortcuts {
  display: flex;
  align-items: center;
  gap: var(--space-2);
}

.icon-link {
  width: 40px;
  height: 40px;
  border-radius: 50%;
  background-color: var(--color-secondary-light);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  text-decoration: none;
  color: var(--color-primary-black);
  font-size: 18px;
}

.icon-link:hover,
.icon-link:focus-visible {
  background-color: var(--color-secondary-soft);
}

.icon {
  line-height: 1;
}

.site-main {
  padding: var(--space-5) var(--space-4) var(--space-6);
}

/* Generic page heading styles matching script look on Acting page */
.page-heading {
  text-align: center;
  margin: 0 0 var(--space-4);
}

.page-heading .script-title {
  font-family: var(--font-heading);
  font-size: var(--font-size-h1);
  line-height: var(--line-height-tight);
  font-weight: var(--font-weight-regular);
}

.page-heading .script-title + .script-swirl {
  font-family: var(--font-heading);
  font-size: 72px;
  line-height: 0.6;
  margin-top: -10px;
}

/* Two-column layout scaffolding similar to image + audio list */
.layout-two-column {
  display: grid;
  grid-template-columns: minmax(0, 1.1fr) minmax(0, 1.4fr);
  gap: var(--space-5);
  align-items: flex-start;
}

@media (max-width: 900px) {
  .header-inner {
    flex-wrap: wrap;
    justify-content: center;
  }

  .primary-nav {
    order: 3;
    width: 100%;
  }

  .primary-nav ul {
    flex-wrap: wrap;
    row-gap: var(--space-1);
  }

  .header-shortcuts {
    order: 2;
  }

  .site-main {
    padding: var(--space-4) var(--space-3) var(--space-5);
  }

  .layout-two-column {
    grid-template-columns: 1fr;
  }
}

/* Photo card framing similar to LEGO image */
.photo-card {
  border-radius: 20px;
  border: 4px solid var(--color-primary-black);
  overflow: hidden;
}

/* Audio track list styling (pill-like rows) */
.audio-track-list {
  display: flex;
  flex-direction: column;
  gap: var(--space-3);
}

.audio-track {
  display: flex;
  flex-direction: column;
  align-items: stretch;
  gap: var(--space-1);
}

.audio-track audio {
  width: 100%;
  border-radius: 999px;
  background-color: var(--color-secondary-soft);
}

.audio-track-label {
  font-family: var(--font-code);
  font-size: var(--font-size-small);
  text-align: center;
  color: var(--color-neutral-mid);
}

/* Footer */
.site-footer {
  background-color: var(--color-primary-black);
  color: var(--color-primary-white);
  padding: var(--space-5) var(--space-4) var(--space-3);
}

.footer-inner {
  max-width: var(--max-width);
  margin: 0 auto;
}

.footer-top {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: var(--space-5);
}

.footer-branding {
  max-width: 260px;
}

.footer-title {
  margin: 0 0 var(--space-1);
  font-size: 14px;
  letter-spacing: 0.22em;
  text-transform: uppercase;
}

.footer-tagline {
  margin: 0;
  font-size: var(--font-size-small);
  color: var(--color-secondary-light);
}

.footer-nav {
  flex: 1 1 auto;
}

.footer-links {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-1) var(--space-3);
}

.footer-links a {
  font-size: var(--font-size-small);
  text-decoration: none;
  color: var(--color-secondary-light);
}

.footer-links a:hover,
.footer-links a:focus-visible {
  color: var(--color-primary-white);
  text-decoration: underline;
}

.footer-bottom {
  margin-top: var(--space-4);
}

.footer-meta {
  margin: 0;
  font-size: 12px;
  color: var(--color-neutral-mid);
}

@media (max-width: 720px) {
  .footer-top {
    flex-direction: column;
    align-items: flex-start;
  }
}
